function executeAction(
    bytes memory _callData,
    bytes32[] memory _subData,
    uint8[] memory _paramMapping,
    bytes32[] memory _returnValues
) public payable virtual override returns (bytes32) {
    Params memory params = parseInputs(_callData);

    params.market = _parseParamAddr(params.market, _paramMapping[0], _subData, _returnValues);
    params.tokenAddr =
        _parseParamAddr(params.tokenAddr, _paramMapping[1], _subData, _returnValues);
    params.amount = _parseParamUint(params.amount, _paramMapping[2], _subData, _returnValues);
    params.from = _parseParamAddr(params.from, _paramMapping[3], _subData, _returnValues);
    params.onBehalf =
        _parseParamAddr(params.onBehalf, _paramMapping[4], _subData, _returnValues);
    params.enableAsColl =
        _parseParamUint(params.enableAsColl ? 1 : 0, _paramMapping[5], _subData, _returnValues)
            == 1;

    (uint256 supplyAmount, bytes memory logData) = _supply(
        params.market,
        params.tokenAddr,
        params.amount,
        params.from,
        params.onBehalf,
        params.enableAsColl
    );
    emit ActionEvent("AaveSupply", logData);
    return bytes32(supplyAmount);
}

function receiveFlashLoan(
    address[] memory _tokens,
    uint256[] memory _amounts,
    uint256[] memory _feeAmounts,
    bytes memory _userData
) external nonReentrant {
    if (msg.sender != VAULT_ADDR) {
        revert UntrustedLender();
    }
    (Recipe memory currRecipe, address wallet) = abi.decode(_userData, (Recipe, address));

    uint256[] memory balancesBefore = new uint256[](_tokens.length);
    for (uint256 i = 0; i < _tokens.length; i++) {
        _tokens[i].withdrawTokens(wallet, _amounts[i]);
        balancesBefore[i] = _tokens[i].getBalance(address(this));
    }

    _executeRecipe(wallet, _getWalletType(wallet), currRecipe, _amounts[0] + _feeAmounts[0]);

    for (uint256 i = 0; i < _tokens.length; i++) {
        uint256 paybackAmount = _amounts[i] + (_feeAmounts[i]);

        if (_tokens[i].getBalance(address(this)) != paybackAmount + balancesBefore[i]) {
            revert WrongPaybackAmountError();
        }

        _tokens[i].withdrawTokens(address(VAULT_ADDR), paybackAmount);
    }
}

function divuu (uint256 x, uint256 y) private pure returns (uint128) {
  unchecked {
    require (y != 0);

    uint256 result;

    if (x <= 0xFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFF)
      result = (x << 64) / y;
    else {
      uint256 msb = 192;
      uint256 xc = x >> 192;
      if (xc >= 0x100000000) { xc >>= 32; msb += 32; }
      if (xc >= 0x10000) { xc >>= 16; msb += 16; }
      if (xc >= 0x100) { xc >>= 8; msb += 8; }
      if (xc >= 0x10) { xc >>= 4; msb += 4; }
      if (xc >= 0x4) { xc >>= 2; msb += 2; }
      if (xc >= 0x2) msb += 1;  // No need to shift xc anymore

      result = (x << 255 - msb) / ((y - 1 >> msb - 191) + 1);
      require (result <= 0xFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFF);

      uint256 hi = result * (y >> 128);
      uint256 lo = result * (y & 0xFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFF);

      uint256 xh = x >> 192;
      uint256 xl = x << 64;

      if (xl < lo) xh -= 1;
      xl -= lo; // We rely on overflow behavior here
      lo = hi << 128;
      if (xl < lo) xh -= 1;
      xl -= lo; // We rely on overflow behavior here

      assert (xh == hi >> 128);

      result += xl / y;
    }

    require (result <= 0xFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFF);
    return uint128 (result);
  }
}

function sqrt(uint256 x) internal pure returns (uint256) {
    if (x == 0) return 0;
    // this block is equivalent to r = uint256(1) << (BitMath.mostSignificantBit(x) / 2);
    // however that code costs significantly more gas
    uint256 xx = x;
    uint256 r = 1;
    if (xx >= 0x100000000000000000000000000000000) {
        xx >>= 128;
        r <<= 64;
    }
    if (xx >= 0x10000000000000000) {
        xx >>= 64;
        r <<= 32;
    }
    if (xx >= 0x100000000) {
        xx >>= 32;
        r <<= 16;
    }
    if (xx >= 0x10000) {
        xx >>= 16;
        r <<= 8;
    }
    if (xx >= 0x100) {
        xx >>= 8;
        r <<= 4;
    }
    if (xx >= 0x10) {
        xx >>= 4;
        r <<= 2;
    }
    if (xx >= 0x8) {
        r <<= 1;
    }
    r = (r + x / r) >> 1;
    r = (r + x / r) >> 1;
    r = (r + x / r) >> 1;
    r = (r + x / r) >> 1;
    r = (r + x / r) >> 1;
    r = (r + x / r) >> 1;
    r = (r + x / r) >> 1; // Seven iterations should be enough
    uint256 r1 = x / r;
    return (r < r1 ? r : r1);
}

constructor (
    address _creator_address,
    address _timelock_address,
    address[8] memory _address_pack
) Owned(_creator_address) {
    // Set timelock
    timelock_address = _timelock_address;

    // Set instances
    FRAX = IFrax(_address_pack[0]);
    FXS = IFxs(_address_pack[1]);
    fraxswap_pair = IFraxswapPair(_address_pack[2]);
    priceFeedFRAXUSD = AggregatorV3Interface(_address_pack[3]);
    priceFeedFXSUSD = AggregatorV3Interface(_address_pack[4]);
    msig_address = _address_pack[5];
    amo_minter = IFraxAMOMinter(_address_pack[6]);
    yield_distributor = veFXSYieldDistributorV4(_address_pack[7]);

    // Set the oracle decimals
    chainlink_frax_usd_decimals = priceFeedFRAXUSD.decimals();
    chainlink_fxs_usd_decimals = priceFeedFXSUSD.decimals();

    // Need to know which token FRAX is (0 or 1)
    address token0 = fraxswap_pair.token0();
    if (token0 == address(FRAX)) frax_is_token0 = true;
    else frax_is_token0 = false;

    // Get the number of TWAMM intervals. Truncation desired
    num_twamm_intervals = swap_period / fraxswap_pair.orderTimeInterval();
}

function isValidZKEmail(
    EmailProof memory emailProof,
    IDKIMRegistry dkimregistry,
    IGroth16Verifier groth16Verifier,
    string[] memory template,
    bytes[] memory templateParams,
    Case stringCase
) internal view returns (EmailProofError) {
    if (bytes(emailProof.maskedCommand).length > COMMAND_BYTES) {
        return EmailProofError.MaskedCommandLength;
    } else if (!_commandMatch(emailProof, template, templateParams, stringCase)) {
        return EmailProofError.MismatchedCommand;
    } else if (!dkimregistry.isDKIMPublicKeyHashValid(emailProof.domainName, emailProof.publicKeyHash)) {
        return EmailProofError.DKIMPublicKeyHash;
    }

    (uint256[2] memory pA, uint256[2][2] memory pB, uint256[2] memory pC) = abi.decode(
        emailProof.proof,
        (uint256[2], uint256[2][2], uint256[2])
    );
    if (!_isValidFieldPoint(pA, pB, pC)) {
        return EmailProofError.InvalidFieldPoint;
    }

    return
        groth16Verifier.verifyProof(pA, pB, pC, toPubSignals(emailProof))
            ? EmailProofError.NoError
            : EmailProofError.EmailProof;
}
